#!/usr/bin/env node
"use strict";

const fs = require("node:fs");
const path = require("node:path");

const repoRoot = process.cwd();
const configPath = path.join(repoRoot, ".nezam/scripts", "config/tools.config.json");

function printHelp() {
  console.log(`sync/sync-ai-folders.js — copy NEZAM .cursor/ governance into generated client trees (per .nezam/scripts/config/tools.config.json).

Usage:
  node .nezam/scripts/sync/sync-ai-folders.js [options]

Options:
  --write              Write generated files (omit for drift-only check; exits 1 if drift)
  --diff               With --write, also print the drift-style file list (check mode always prints drift)
  --status             Print one-line ✓ / ⚠ per mirrored tool target (included memory-inject roots); exits 1 if drift
  --target=<tool-id>   Sync only one tool (e.g. claude, codex, gemini). Default skips id "cursor".

Examples:
  pnpm run ai:sync
  node .nezam/scripts/sync/sync-ai-folders.js --write
  node .nezam/scripts/sync/sync-ai-folders.js
  node .nezam/scripts/sync/sync-ai-folders.js --status
  node .nezam/scripts/sync/sync-ai-folders.js --target=claude --write

Tool ids (see .nezam/scripts/config/tools.config.json): cursor, claude, codex, copilot, opencode, antigravity, gemini, qwen, kilo

Exit codes:
  0  No drift (check mode), or --write finished, or --status all mirrors match
  1  Drift detected in check mode (no --write), or --status found drift
  2  Bad CLI flags or unknown --target value
`);
}

const rawArgs = process.argv.slice(2);
if (rawArgs.includes("--help") || rawArgs.includes("-h")) {
  printHelp();
  process.exit(0);
}

for (const arg of rawArgs) {
  if (!arg.startsWith("-")) continue;
  if (arg === "--write" || arg === "--diff" || arg === "--status") continue;
  if (arg.startsWith("--target=")) continue;
  console.error(
    `sync-ai-folders: unknown option "${arg}"\n` +
      "  node .nezam/scripts/sync/sync-ai-folders.js --help\n" +
      "  Typical apply after editing .cursor/: pnpm run ai:sync"
  );
  process.exit(2);
}

const args = new Set(rawArgs);
const writeMode = args.has("--write");
const diffMode = args.has("--diff");
const statusMode = args.has("--status");
const targetArg = [...args].find((arg) => arg.startsWith("--target="));
const targetFilter = targetArg ? targetArg.split("=")[1] : null;

const BANNER =
  "<!-- generated by .nezam/scripts/sync/sync-ai-folders.js — do not edit; edit .cursor/ and run pnpm ai:sync -->";

function readUtf8(filePath) {
  return fs.readFileSync(filePath, "utf8");
}

function ensureDir(dirPath) {
  fs.mkdirSync(dirPath, { recursive: true });
}

function walkFiles(dirPath, acc = []) {
  if (!fs.existsSync(dirPath)) return acc;
  for (const entry of fs.readdirSync(dirPath, { withFileTypes: true })) {
    if (entry.name === ".DS_Store") continue;
    const fullPath = path.join(dirPath, entry.name);
    if (entry.isDirectory()) {
      walkFiles(fullPath, acc);
    } else {
      acc.push(fullPath);
    }
  }
  return acc;
}

function relativeFromRepo(filePath) {
  return path.relative(repoRoot, filePath).replaceAll(path.sep, "/");
}

function parseFrontmatter(markdown) {
  if (!markdown.startsWith("---\n")) return { description: "", body: markdown };
  const end = markdown.indexOf("\n---\n", 4);
  if (end === -1) return { description: "", body: markdown };
  const fm = markdown.slice(4, end);
  const body = markdown.slice(end + 5);
  let description = "";
  for (const line of fm.split("\n")) {
    const match = line.match(/^description:\s*(.+)$/);
    if (match) {
      description = match[1].trim().replace(/^["']|["']$/g, "");
      break;
    }
  }
  return { description, body };
}

function escapeToml(multiline) {
  return multiline.replaceAll('"""', '\\"\\"\\"');
}

function rewriteLinks(markdown, targetRoot) {
  return markdown.replace(/\]\(([^)]+)\)/g, (whole, href) => {
    if (
      href.startsWith("http://") ||
      href.startsWith("https://") ||
      href.startsWith("#")
    ) {
      return whole;
    }
    const abs = path.resolve(repoRoot, targetRoot, href);
    const rel = path.relative(path.join(repoRoot, targetRoot), abs).replaceAll(path.sep, "/");
    return `](${rel.startsWith(".") ? rel : `./${rel}`})`;
  });
}

function buildMemoryContent(templatePath) {
  const template = readUtf8(path.join(repoRoot, templatePath)).trim();
  const commandFiles = walkFiles(path.join(repoRoot, ".cursor", "commands"))
    .filter((f) => f.endsWith(".md"))
    .map((f) => path.basename(f))
    .sort();
  const agentFiles = walkFiles(path.join(repoRoot, ".cursor", "agents"))
    .filter((f) => f.endsWith(".md"))
    .map((f) => path.basename(f))
    .sort();
  const skillDirs = fs
    .readdirSync(path.join(repoRoot, ".cursor", "skills"), { withFileTypes: true })
    .filter((d) => d.isDirectory())
    .map((d) => d.name)
    .sort();
  const ruleFiles = walkFiles(path.join(repoRoot, ".cursor", "rules"))
    .filter((f) => f.endsWith(".mdc"))
    .sort((a, b) => a.localeCompare(b))
    .map((f) => relativeFromRepo(f));

  const joinList = (items) => items.map((x) => `- \`${x}\``).join("\n");
  return [
    BANNER,
    "",
    template,
    "",
    "## Synced command index",
    joinList(commandFiles),
    "",
    "## Synced agent index",
    joinList(agentFiles),
    "",
    "## Synced skill index",
    joinList(skillDirs),
    "",
    "## Synced rule sources",
    joinList(ruleFiles),
    "",
  ].join("\n");
}

function computeOutputsForTool(tool) {
  const outputs = [];
  for (const target of tool.targets || []) {
    const kind = target.kind;
    if (kind === "memory-inject") {
      outputs.push({
        path: target.path,
        content: buildMemoryContent(target.template),
      });
      continue;
    }

    const sourceAbs = path.join(repoRoot, target.source);
    const sourceFiles = walkFiles(sourceAbs);
    for (const src of sourceFiles) {
      const rel = path.relative(sourceAbs, src);
      const relUnix = rel.replaceAll(path.sep, "/");

      if (kind === "rules-copy" && !src.endsWith(".mdc")) continue;
      if (kind === "markdown-copy" && !src.endsWith(".md")) continue;
      if (kind === "toml-commands" && !src.endsWith(".md")) continue;

      const srcText = readUtf8(src);

      if (kind === "toml-commands") {
        const { description, body } = parseFrontmatter(srcText);
        const fileName = path.basename(src, ".md");
        const content = [
          "# generated by sync/sync-ai-folders.js",
          `name = "${fileName}"`,
          `description = "${(description || fileName).replaceAll('"', '\\"')}"`,
          `prompt = """\n${escapeToml(body.trim())}\n"""`,
          "",
        ].join("\n");
        outputs.push({
          path: `${target.path}/${fileName}.toml`,
          content,
        });
      } else {
        const rewritten = rewriteLinks(srcText, target.path);
        const content = `${BANNER}\n\n${rewritten}`;
        outputs.push({
          path: `${target.path}/${relUnix}`,
          content,
        });
      }
    }
  }
  return outputs;
}

function collectDiffsForTool(tool) {
  const diffs = [];
  const outputs = computeOutputsForTool(tool);
  for (const out of outputs) {
    const abs = path.join(repoRoot, out.path);
    const exists = fs.existsSync(abs);
    const current = exists ? readUtf8(abs) : null;
    const changed = !exists || current !== out.content;
    if (changed) diffs.push(relativeFromRepo(abs));
  }
  return diffs;
}

function main() {
  const config = JSON.parse(readUtf8(configPath));
  const tools = (config.tools || []).filter((tool) =>
    targetFilter ? tool.id === targetFilter : tool.id !== "cursor"
  );

  if (statusMode && writeMode) {
    console.error("sync-ai-folders: --status cannot be combined with --write");
    process.exit(2);
  }

  if (statusMode) {
    let anyDrift = false;
    for (const tool of tools) {
      const toolDiffs = collectDiffsForTool(tool);
      if (toolDiffs.length === 0) {
        console.log(`${tool.id}: ✓ in sync`);
      } else {
        anyDrift = true;
        console.log(`${tool.id}: ⚠ drifted (${toolDiffs.length} file(s))`);
      }
    }
    process.exit(anyDrift ? 1 : 0);
  }

  if (targetFilter && tools.length === 0) {
    console.error(
      `Unknown target tool: ${targetFilter}\n` +
        "  node .nezam/scripts/sync/sync-ai-folders.js --target=<tool-id> --write\n" +
        "  Valid ids are listed under tools[].id in .nezam/scripts/config/tools.config.json (e.g. claude, codex, gemini)."
    );
    process.exit(2);
  }

  const diffs = [];
  let writes = 0;

  for (const tool of tools) {
    const outputs = computeOutputsForTool(tool);
    for (const out of outputs) {
      const abs = path.join(repoRoot, out.path);
      const exists = fs.existsSync(abs);
      const current = exists ? readUtf8(abs) : null;
      const changed = !exists || current !== out.content;

      if (changed) {
        diffs.push(relativeFromRepo(abs));
        if (writeMode) {
          ensureDir(path.dirname(abs));
          fs.writeFileSync(abs, out.content, "utf8");
          writes += 1;
        }
      }
    }
  }

  if (diffMode || !writeMode) {
    if (diffs.length === 0) {
      console.log("No sync drift detected.");
    } else {
      console.log("Sync drift detected:");
      for (const item of diffs.sort()) console.log(` - ${item}`);
    }
  }

  if (writeMode) {
    console.log(`Synced files: ${writes}`);
  }

  process.exit(diffs.length > 0 && !writeMode ? 1 : 0);
}

main();
